    $x = count($browsers);
    for ($i=0; $i<$x; $i++) {
        $browser = $browsers[$i];
        $n = stristr($nua, $browser);
        if (strlen($n) > 0) {
            $version = '';
            $nav = $browser;
            $j = strpos($nua, $nav) + $n + strlen($nav) + 1;
            for (; $j<=$l; $j++){
                $s = substr($nua, $j, 1);
                if (is_numeric($version.$s)) {
                    $version .= $s;
                } else {
