    public function actionEditableSaver()
    {
        $id = Yii::app()->request->getPost('pk');
        if(empty($id)){
            throw new CHttpException(404, Yii::t("D2filesModule.model","The requested record does not exist."));
        }

        $m = D2files::model();
        $model = $m->findByPk($id);
        if ($model === null) {
            throw new CHttpException(404, Yii::t("D2filesModule.model","The requested record does not exist."));
        }

