            $this->cache_mode = 'DB_WRITE_CACHE';
            $now = date( "YmdHis", time() ); 
            // bb hack for timemanagment start
            if( $this->cache_group == 'frontend' ) {
                $this->_figure_out_cachetime_for_frontend();
            } 
            // bb hack for timemanagment stop
            switch ( $action ) {
