	//print $s."<br>\n";
	if ($returnvalue)
	{
	    if ($hideerrors) return @eval('return '.$s.';');
	    else return eval('return '.$s.';');
	}
	else
	{
	    if ($hideerrors) @eval($s);
	    else eval($s);
	}
}

