static function getSearchResultsInDateRange($query,$start_date,$end_date,$featured = false) {
	$events = array();
	if ($featured) {
		$featured = " AND btx_events_events.featured = 'on' ";
	}

	$words = explode(" ",$query);
	$qwords = array();
	if ($words) {
		foreach ($words as $word) {
