public function getTables($prefix = null)
{
    $metadata = \Laminas\Db\Metadata\Source\Factory::createSourceFromAdapter($this->db);
    $tmp_tables_list = $metadata->getTableNames();

    if ($prefix === null) {
        $prefix = PREFIX_DB;
    }

    $tables_list = array();
