static function getStaffMembers($criteria=array()) {
    global $cfg;

    $members = static::objects();

    if (isset($criteria['available'])) {
        $members = $members->filter(array(
            'onvacation' => 0,
            'isactive' => 1,
        ));
    }

    $members = self::nsort($members);

    $users=array();
    foreach ($members as $M) {
        $users[$M->getId()] = $M->getName();
    }

    return $users;
