 */
public static function validate_type($type)
{
    switch ($type) {
        case 'artist':
        case 'album':
        case 'tag':
        case 'song':
        case 'video':
        case 'tvshow':
        case 'tvshow_season':
        case 'tvshow_episode':
        case 'movie':
