    if (!$asset) {
        throw $this->createNotFoundException('Asset not found');
    }
    $zipFile = PIMCORE_SYSTEM_TEMP_DIRECTORY . '/download-zip-' . $request->get('jobId') . '.zip';
    $suggestedFilename = $asset->getFilename();
    if (empty($suggestedFilename)) {
